    related_articles: ["čl. 201. ZKP","čl. 402. ZKP","čl. 222. ZKP","čl. 220. ZKP","čl. 314. ZKP","čl. 95. ZKP"],
    headnote: "podaljšanje pripora - utemeljen sum - ponovitvena nevarnost - neogibna potrebnost - sorazmernost",
